import {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  ImageRun, AlignmentType, WidthType, BorderStyle, ShadingType,
  VerticalAlign, UnderlineType, TableLayoutType, HeightRule
} from "docx";

// Imagem do cabeçalho embutida em base64
const CABECALHO_B64 = "";

const MARGIN = 567;
const PAGE_W = 11906;
const CONTENT_W = PAGE_W - MARGIN * 2;
const FONT = "Arial";
const SP = { after: 0, line: 200, lineRule: "atLeast" };

const B_SINGLE = { style: BorderStyle.SINGLE, size: 4, color: "000000" };
const B_NONE   = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const BORDERS_ALL  = { top: B_SINGLE, bottom: B_SINGLE, left: B_SINGLE, right: B_SINGLE };
const BORDERS_NONE = { top: B_NONE, bottom: B_NONE, left: B_NONE, right: B_NONE };

function run(text, { bold=false, italic=false, underline=false, size=28 } = {}) {
  return new TextRun({
    text, font: FONT, size, bold, italics: italic,
    underline: underline ? { type: UnderlineType.SINGLE } : undefined,
  });
}

function para(children, align = AlignmentType.LEFT) {
  return new Paragraph({ children, spacing: SP, alignment: align });
}

function cell(children, { w, span, fill, borders } = {}) {
  return new TableCell({
    children,
    columnSpan: span,
    width: w ? { size: w, type: WidthType.DXA } : undefined,
    shading: fill ? { fill, type: ShadingType.CLEAR } : undefined,
    verticalAlign: VerticalAlign.CENTER,
    borders: borders || BORDERS_ALL,
    margins: { top: 40, bottom: 40, left: 100, right: 100 },
  });
}

function makeHeaderTable(input) {
  const c1 = Math.round(CONTENT_W * 0.340);
  const c2 = Math.round(CONTENT_W * 0.340);
  const c3 = Math.round(CONTENT_W * 0.207);
  const c4 = CONTENT_W - c1 - c2 - c3;

  const row1 = new TableRow({
    height: { value: 500, rule: HeightRule.ATLEAST },
    children: [
      cell([para([run("ROTEIRO DE ESTUDO", { bold: true, size: 40 })], AlignmentType.CENTER)],
        { w: c1 + c2, span: 2, fill: "D9D9D9" }),
      cell([para([run(input.mes.toUpperCase(), { bold: true, size: 40 })], AlignmentType.CENTER)],
        { w: c3, fill: "D9D9D9" }),
      cell([para([run(input.ano, { bold: true, size: 40 })], AlignmentType.CENTER)],
        { w: c4, fill: "D9D9D9" }),
    ]
  });

  const row2 = new TableRow({
    children: [
      cell([para([run("SÉRIE/ANO:", { size: 20 })]), para([run(input.serie, { bold: true, size: 28 })])],
        { w: c1, fill: "FFFFFF" }),
      cell([para([run("TURMA:", { size: 20 })]), para([run(input.turma, { bold: true, size: 28 })])],
        { w: c2, fill: "FFFFFF" }),
      cell([para([run("TURNO:", { size: 20 })]), para([run(input.turno.toUpperCase(), { bold: true, size: 28 })])],
        { w: c3 + c4, span: 2, fill: "FFFFFF" }),
    ]
  });

  return new Table({
    width: { size: CONTENT_W, type: WidthType.DXA },
    columnWidths: [c1, c2, c3, c4],
    rows: [row1, row2],
    layout: TableLayoutType.FIXED,
  });
}

function makeAviso() {
  return new Table({
    width: { size: CONTENT_W, type: WidthType.DXA },
    columnWidths: [CONTENT_W],
    rows: [new TableRow({ children: [
      new TableCell({
        borders: BORDERS_NONE,
        shading: { fill: "FFFF00", type: ShadingType.CLEAR },
        margins: { top: 0, bottom: 0, left: 0, right: 0 },
        children: [para([run("Estudar também pelas revisões do caderno.", { bold: true, italic: true, size: 24 })], AlignmentType.RIGHT)]
      })
    ]})]
  });
}

function makeObsTable(texto) {
  return new Table({
    width: { size: CONTENT_W, type: WidthType.DXA },
    columnWidths: [CONTENT_W],
    rows: [new TableRow({ children: [
      new TableCell({
        width: { size: CONTENT_W, type: WidthType.DXA },
        shading: { fill: "FFFF00", type: ShadingType.CLEAR },
        borders: BORDERS_ALL,
        margins: { top: 60, bottom: 60, left: 120, right: 120 },
        children: [
          para([run("Observação", { bold: true, underline: true, size: 28 })]),
          new Paragraph({
            spacing: SP,
            indent: { left: 360, hanging: 360 },
            bullet: { level: 0 },
            children: [
              run("As notas de ", { size: 28 }),
              run("Formação Humana, Artes e Educação Física", { bold: true, size: 28 }),
              run(" serão atribuídas através dos trabalhos realizados em sala de aula.", { size: 28 }),
            ]
          }),
        ]
      })
    ]})]
  });
}

export async function POST(req) {
  try {
    const input = await req.json();

    const imageData = Buffer.from(CABECALHO_B64, "base64");
    const children = [];

    // 1. Imagem cabeçalho
    children.push(para([
      new ImageRun({ data: imageData, transformation: { width: 762, height: 75 }, type: "jpg" })
    ]));

    // 2. Tabela cabeçalho
    children.push(makeHeaderTable(input));

    // 3. Espaço
    children.push(para([]));

    // 4. Aviso amarelo
    children.push(makeAviso());

    // 5. Espaço
    children.push(para([]));

    // 6. Dias
    for (const dia of input.dias) {
      children.push(para([run(dia.cabecalho, { bold: true, size: 28 })]));

      for (const mat of dia.materias) {
        children.push(para([run(`- ${mat.nome}`, { bold: true, size: 28 })]));
        if (mat.subtitulo) {
          children.push(para([run(mat.subtitulo, { bold: true, italic: true, size: 28 })]));
        }
        for (const t of mat.topicos) {
          children.push(para([run(`* ${t}`, { size: 28 })]));
        }
        if (mat.paginas) {
          children.push(para([
            run("Páginas: ", { bold: true, size: 28 }),
            run(mat.paginas, { size: 28 }),
          ]));
        }
        children.push(para([]));
      }
    }

    // 7. Observação
    children.push(makeObsTable(input.observacao));

    const doc = new Document({
      sections: [{
        properties: {
          page: {
            size: { width: PAGE_W, height: 16838 },
            margin: { top: MARGIN, right: MARGIN, bottom: MARGIN, left: MARGIN },
          }
        },
        children,
      }]
    });

    const buffer = await Packer.toBuffer(doc);

    return new Response(buffer, {
      status: 200,
      headers: {
        "Content-Type": "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
        "Content-Disposition": `attachment; filename="Roteiro_${input.serie.replace(/\s/g,'_')}_${input.turma}_${input.mes}.docx"`,
      }
    });

  } catch (err) {
    console.error(err);
    return Response.json({ error: err.message }, { status: 500 });
  }
}
